const payload = $json.body || $json || {};

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return '';
}

function extractMessage(body) {
  const candidates = [
    body?.data?.message?.conversation,
    body?.data?.message?.extendedTextMessage?.text,
    body?.data?.message?.imageMessage?.caption,
    body?.data?.message?.videoMessage?.caption,
    body?.message?.conversation,
    body?.message?.extendedTextMessage?.text,
    body?.message?.imageMessage?.caption,
    body?.message?.videoMessage?.caption,
    body?.text,
    body?.conversation
  ];
  return String(pick(...candidates, '')).trim();
}

function extractButtonId(body) {
  return String(
    pick(
      body?.data?.message?.buttonsResponseMessage?.selectedButtonId,
      body?.data?.message?.templateButtonReplyMessage?.selectedId,
      body?.data?.message?.interactiveResponseMessage?.nativeFlowResponseMessage?.paramsJson,
      body?.buttonsResponseMessage?.selectedButtonId,
      body?.button?.id,
      body?.interactive?.button_reply?.id,
      ''
    )
  ).trim();
}

function firstName(name) {
  const clean = String(name || '').trim();
  return clean ? clean.split(/\s+/)[0] : '';
}

function extractUrl(text) {
  const match = String(text || '').match(/https?:\/\/[^\s]+/i);
  return match ? match[0] : '';
}

function safeSessionNumber(value) {
  return String(value || '').replace(/@.*/, '').replace(/\D/g, '');
}

const remoteJid = String(
  pick(
    payload?.data?.key?.remoteJid,
    payload?.key?.remoteJid,
    payload?.data?.from,
    payload?.from,
    ''
  )
).trim();

const whatsappNumber = remoteJid
  ? safeSessionNumber(remoteJid)
  : String(pick(payload?.phone, payload?.number, '')).replace(/\D/g, '');

const sessionId = whatsappNumber || `sem_sessao_${Date.now()}`;
const pushName = String(pick(payload?.data?.pushName, payload?.pushName, payload?.notifyName, '')).trim();

const buttonId = extractButtonId(payload);
const isContinuacao = buttonId.startsWith('continuar_conversa::');
const retomadaRefKey = isContinuacao ? buttonId.split('::')[1] || '' : '';

const rawMessage = extractMessage(payload);
const userMessage = isContinuacao
  ? 'Continuar conversa sobre o carrinho abandonado'
  : (rawMessage || 'Mensagem vazia');

const incomingUrl = extractUrl(rawMessage);

return [{
  json: {
    raw_payload: payload,
    source: 'whatsapp_webhook',
    remote_jid: remoteJid,
    whatsapp_number: whatsappNumber,
    session_id: sessionId,
    user_message: userMessage,
    customer_name: pushName,
    first_name: firstName(pushName),
    incoming_url: incomingUrl,
    received_at: new Date().toISOString(),
    cart_url: 'https://www.frigelar.com.br/cart',
    site_base_url: 'https://www.frigelar.com.br/',
    button_id: buttonId,
    is_continuacao: isContinuacao,
    produto_contexto: '',
    retomada_ref_key: retomadaRefKey,
    source_flow_hint: isContinuacao ? 'recuperacao_carrinho' : '',
    journey_stage_hint: isContinuacao ? 'retomada_pos_disparo' : ''
  }
}];

const j = $json || {};

const categories = [
  { key: 'ar_condicionado', title: 'Ar Condicionado', url: 'https://www.frigelar.com.br/ar-condicionado/c' },
  { key: 'eletrodomesticos', title: 'Eletrodomésticos', url: 'https://www.frigelar.com.br/eletrodomesticos/c' },
  { key: 'eletroportateis', title: 'Eletroportáteis', url: 'https://www.frigelar.com.br/eletroportateis/c' },
  { key: 'climatizacao', title: 'Climatização', url: 'https://www.frigelar.com.br/climatizacao/c' },
  { key: 'ferramentas', title: 'Ferramentas', url: 'https://www.frigelar.com.br/ferramentas/c' },
  { key: 'pecas', title: 'Peças e Acessórios', url: 'https://www.frigelar.com.br/pecas-e-acessorios/c' },
  { key: 'refrigeracao_comercial', title: 'Refrigeração Comercial', url: 'https://www.frigelar.com.br/refrigeracao-comercial/c' },
  { key: 'servicos', title: 'Serviços', url: 'https://www.frigelar.com.br/' },
  { key: 'impulsiona', title: 'Parceiros Impulsiona', url: 'https://impulsiona.frigelar.com.br/' }
];

function normalizeSearch(text) {
  return String(text || '')
    .replace(/https?:\/\/[^\s]+/gi, ' ')
    .replace(/[^\p{L}\p{N}\s\-\/]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeCompare(text) {
  return String(text || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function detectCategory(text) {
  const t = normalizeCompare(text);

  if (/(impulsiona|parceiro impulsiona|parceiros impulsiona|programa impulsiona|portal impulsiona|area do parceiro|área do parceiro|instalador parceiro|instaladores parceiros|cadastro no programa|cadastro do programa|programa de parceiros|portal do parceiro|parceiros)/.test(t)) {
    return categories.find(c => c.key === 'impulsiona');
  }

  if (/(ar condicionado|ar-condicionado|split|inverter|cassete|piso teto|multi split)/.test(t)) {
    return categories.find(c => c.key === 'ar_condicionado');
  }

  if (/(eletrodomestico|eletrodoméstico|geladeira|refrigerador|freezer|fogao|fogão|microondas|lava e seca|lavadora|secadora)/.test(t)) {
    return categories.find(c => c.key === 'eletrodomesticos');
  }

  if (/(eletroportatil|eletroportátil|air fryer|cafeteira|liquidificador|batedeira|aspirador)/.test(t)) {
    return categories.find(c => c.key === 'eletroportateis');
  }

  if (/(climatizacao|climatização|ventilador|umidificador|desumidificador|climatizador)/.test(t)) {
    return categories.find(c => c.key === 'climatizacao');
  }

  if (/(ferramenta|furadeira|parafusadeira|serra|multimetro|multímetro)/.test(t)) {
    return categories.find(c => c.key === 'ferramentas');
  }

  if (/(peca|peça|acessorio|acessório|controle remoto|capacitor|motor|placa)/.test(t)) {
    return categories.find(c => c.key === 'pecas');
  }

  if (/(refrigeracao comercial|refrigeração comercial|camara fria|câmara fria|expositor|ilha|balcao refrigerado|balcão refrigerado)/.test(t)) {
    return categories.find(c => c.key === 'refrigeracao_comercial');
  }

  if (/(servico|serviço|instalacao|instalação|manutencao|manutenção|assistencia|assistência)/.test(t)) {
    return categories.find(c => c.key === 'servicos');
  }

  return null;
}

const rawQuery = normalizeSearch(j.user_message || '');
const detectedCategory = detectCategory(j.user_message || '');

const siteLookupUrl = j.incoming_url
  ? j.incoming_url
  : (detectedCategory?.key === 'impulsiona'
      ? detectedCategory.url
      : (rawQuery
          ? `https://www.frigelar.com.br/busca?q=${encodeURIComponent(rawQuery)}`
          : 'https://www.frigelar.com.br/'));

return [{
  json: {
    ...j,
    search_term: rawQuery,
    detected_category: detectedCategory ? detectedCategory.key : '',
    detected_category_title: detectedCategory ? detectedCategory.title : '',
    detected_category_url: detectedCategory ? detectedCategory.url : '',
    site_lookup_url: siteLookupUrl,
    category_catalog: categories,
    category_catalog_text: categories.map(cat => `${cat.title}: ${cat.url}`).join('\n')
  }
}];

const j = $json || {};

function cleanText(value) {
  return String(value || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function extractMatch(html, regex) {
  const match = String(html || '').match(regex);
  return match ? cleanText(match[1]) : '';
}

function absolutize(url) {
  const value = String(url || '').trim();
  if (!value) return '';
  if (/^https?:\/\//i.test(value)) return value;
  if (value.startsWith('/')) return `https://www.frigelar.com.br${value}`;
  return `https://www.frigelar.com.br/${value.replace(/^\/+/, '')}`;
}

function uniqueBy(arr, keyFn) {
  const seen = new Set();
  const out = [];
  for (const item of arr) {
    const key = keyFn(item);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    out.push(item);
  }
  return out;
}

const html = String(j.data || j.body || '');
const siteTitle = extractMatch(html, /<title[^>]*>([\s\S]*?)<\/title>/i);
const metaDescription = extractMatch(html, /<meta[^>]+name=["']description["'][^>]+content=["']([\s\S]*?)["'][^>]*>/i) ||
  extractMatch(html, /<meta[^>]+content=["']([\s\S]*?)["'][^>]+name=["']description["'][^>]*>/i);
const h1 = extractMatch(html, /<h1[^>]*>([\s\S]*?)<\/h1>/i);

const productLinks = [];
const categoryLinks = [];
const anchorRegex = /<a[^>]+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
let match;
while ((match = anchorRegex.exec(html)) !== null) {
  const href = absolutize(match[1]);
  const text = cleanText(match[2]).slice(0, 120);
  if (!href || !text) continue;

  if (/frigelar\.com\.br\/(busca\?q=|[^\/?#]+\/p|[^\/?#]+-p\/|produto|p\/)/i.test(href) || /btu|eos|split|adega|cervejeira|freezer|geladeira|micro-ondas|cooktop|ventilador/i.test(text)) {
    productLinks.push({ text, href });
  }

  if (/frigelar\.com\.br\/[^\/?#]+\/c/i.test(href) || /(categoria|linha|ar condicionado|eletrodomésticos|eletroportáteis|climatização|ferramentas|peças|refrigeração comercial)/i.test(text)) {
    categoryLinks.push({ text, href });
  }
}

const topProductLinks = uniqueBy(productLinks, item => item.href).slice(0, 5);
const topCategoryLinks = uniqueBy(categoryLinks, item => item.href).slice(0, 5);

const siteContextSummary = [
  siteTitle ? `Título da página: ${siteTitle}.` : '',
  h1 ? `Cabeçalho principal: ${h1}.` : '',
  metaDescription ? `Descrição: ${metaDescription}.` : '',
  topProductLinks.length ? `Produtos encontrados: ${topProductLinks.map(item => `${item.text} (${item.href})`).join(' | ')}.` : '',
  topCategoryLinks.length ? `Categorias encontradas: ${topCategoryLinks.map(item => `${item.text} (${item.href})`).join(' | ')}.` : ''
].filter(Boolean).join(' ');

return [{
  json: {
    ...j,
    site_page_title: siteTitle,
    site_page_description: metaDescription,
    site_page_h1: h1,
    top_product_links: topProductLinks,
    top_category_links: topCategoryLinks,
    top_product_links_text: topProductLinks.length
      ? topProductLinks.map(item => `${item.text}: ${item.href}`).join('\n')
      : '',
    top_category_links_text: topCategoryLinks.length
      ? topCategoryLinks.map(item => `${item.text}: ${item.href}`).join('\n')
      : '',
    site_context_summary: siteContextSummary || 'Contexto do site não identificado com segurança.'
  }
}];

const ctx = $('CORE | 05 Code Extrair Contexto Site').item.json;
const raw = String($json.output || '').trim();

function fallbackRoute(message) {
  const text = String(message || '').toLowerCase();
  if (/(carrinho|checkout|comprar|fechar|pagamento|frete|prazo|link)/i.test(text)) return 'conversao';
  if (/(compar|versus|vs|diferença|melhor entre)/i.test(text)) return 'comparador';
  if (/(categoria|linha|opção|opcoes|ambiente|uso|qual escolher)/i.test(text)) return 'categorias';
  if (/(garantia|troca|pedido|entrega|site|login|cadastro|atendimento|institucional)/i.test(text)) return 'site_geral';
  return 'produtos';
}

let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {};
}

const routeSpecialist = ['produtos','site_geral','categorias','comparador','conversao'].includes(parsed.route_specialist)
  ? parsed.route_specialist
  : fallbackRoute(ctx.user_message);

return [{
  json: {
    ...ctx,
    router_raw: raw,
    route_specialist: routeSpecialist,
    intent: parsed.intent || 'nao_classificado',
    lead_stage: parsed.lead_stage || 'avaliacao',
    route_reason: parsed.reason || 'fallback'
  }
}];

const ctx = $('CORE | 07 Code Parse Router').item.json;

function tryParseJson(text) {
  const raw = String(text || '').trim();
  if (!raw) return {};
  try {
    return JSON.parse(raw);
  } catch (e) {}

  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced) {
    try {
      return JSON.parse(fenced[1]);
    } catch (e) {}
  }

  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const candidate = raw.slice(start, end + 1);
    try {
      return JSON.parse(candidate);
    } catch (e) {}
  }

  return {};
}

function normalizeText(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function isImpulsionaIntent(context) {
  const text = normalizeText([
    context.user_message,
    context.detected_category,
    context.detected_category_title,
    context.route_specialist,
    context.search_term
  ].join(' '));

  return /(impulsiona|parceiro impulsiona|parceiros impulsiona|programa impulsiona|portal impulsiona|portal do parceiro|area do parceiro|area de parceiro|instalador parceiro|instaladores parceiros|cadastro no programa|cadastro do programa|programa de parceiros)/.test(text);
}

function sanitizeImpulsionaLink(text, fixedLink) {
  let output = String(text || '');

  output = output.replace(/https?:\/\/www\.frigelar\.com\.br\/instaladores-parceiros[^\s]*/gi, fixedLink);
  output = output.replace(/https?:\/\/www\.frigelar\.com\.br\/instalador[^\s]*/gi, fixedLink);
  output = output.replace(/https?:\/\/impulsiona\.frigelar\.com\.br\/Technician[^\s]*/gi, fixedLink);
  output = output.replace(/https?:\/\/www\.frigelar\.com\.br\/seg-instaladores\/c[^\s]*/gi, fixedLink);

  return output;
}

const raw = String($json.output || '').trim();
const parsed = tryParseJson(raw);

let replyText = String(parsed.reply_text || raw || '').trim();
let recommendedLink = String(parsed.recommended_link || '').trim();
const needsHuman = Boolean(parsed.needs_human);
const handoffReason = String(parsed.handoff_reason || '').trim();
const specialist = String(parsed.specialist || ctx.route_specialist || 'especialista').trim();

const fixedImpulsionaLink = 'https://impulsiona.frigelar.com.br/';
const impulsionaIntent = isImpulsionaIntent(ctx);

if (impulsionaIntent) {
  recommendedLink = fixedImpulsionaLink;
  replyText = sanitizeImpulsionaLink(replyText, fixedImpulsionaLink);

  if (!replyText.includes(fixedImpulsionaLink)) {
    replyText = `${replyText}\n${fixedImpulsionaLink}`.trim();
  }
} else if (recommendedLink && !replyText.includes(recommendedLink)) {
  replyText = `${replyText}\n${recommendedLink}`.trim();
}

if (needsHuman && !/atendimento humano/i.test(replyText)) {
  replyText = `${replyText}\nSe você preferir, eu também posso encaminhar isso para atendimento humano.`.trim();
}

if (!replyText) {
  replyText = 'Posso te ajudar melhor se você me disser um pouco mais do que precisa.';
}

return [{
  json: {
    ...ctx,
    reply_text: replyText,
    specialist_reply_text: replyText,
    needs_human: needsHuman,
    handoff_reason: handoffReason,
    specialist: specialist,
    recommended_link: recommendedLink,
    raw_specialist_output: raw
  }
}];

