function safeText(value, fallback = '') {
  const text = String(value || '').trim();
  return text || String(fallback || '').trim();
}

function normalize(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function getEnv(name, fallback = '') {
  try {
    return safeText($env[name], fallback);
  } catch (e) {
    return safeText(fallback);
  }
}

function inferSegment(input) {
  const text = normalize([
    input.user_message,
    input.site_page_title,
    input.site_page_description,
    input.site_context_summary,
    input.top_product_links_text,
    input.top_category_links_text
  ].join(' '));

  if (/(ar condicionado|ar-condicionado|split|climatiz|ventil|umidificador)/i.test(text)) return 'climatizacao';
  if (/(geladeira|refrigerador|freezer|frigobar|chopeira|cervejeira|adega|bebidas|refrigeracao comercial)/i.test(text)) return 'refrigeracao';
  if (/(peca|peça|acessorio|acessório|controle|placa|motor|ferramenta|manutencao|manutenção|instalacao|instalação)/i.test(text)) return 'pecas';
  if (/(air fryer|forno|cooktop|cafeteira|liquidificador|eletro|eletrodomestico|eletrodoméstico|eletroportatil|eletroportátil)/i.test(text)) return 'eletro';
  return 'recuperacao';
}

function buildSellerProfile(nameEnv, fallbackName, numberEnv, defaultInternalNumber) {
  return {
    nome: getEnv(nameEnv, fallbackName),
    numero: getEnv(numberEnv, defaultInternalNumber)
  };
}

function getBaseContext() {
  try {
    return $('CLIENTE | 18 Code Parse Resposta Especialista').item.json || {};
  } catch (e) {
    return $json || {};
  }
}

const sendResponse = $json || {};
const baseContext = getBaseContext();
const j = {
  ...baseContext,
  whatsapp_send_status: safeText(sendResponse.statusCode, ''),
  whatsapp_send_response: typeof sendResponse.body === 'string'
    ? safeText(sendResponse.body, '')
    : JSON.stringify(sendResponse.body || {})
};

const segmento = inferSegment(j);
const defaultInternalNumber = getEnv('VENDEDOR_INTERNO_PADRAO', '555192875343');

const sellerPool = {
  premium: buildSellerProfile('VENDEDOR_PREMIUM', 'Closer Premium', 'VENDEDOR_PREMIUM_NUMERO', defaultInternalNumber),
  climatizacao: buildSellerProfile('VENDEDOR_CLIMATIZACAO', 'Closer Climatização', 'VENDEDOR_CLIMATIZACAO_NUMERO', defaultInternalNumber),
  refrigeracao: buildSellerProfile('VENDEDOR_REFRIGERACAO', 'Closer Refrigeração', 'VENDEDOR_REFRIGERACAO_NUMERO', defaultInternalNumber),
  eletro: buildSellerProfile('VENDEDOR_ELETRO', 'Closer Eletro', 'VENDEDOR_ELETRO_NUMERO', defaultInternalNumber),
  pecas: buildSellerProfile('VENDEDOR_PECAS', 'Closer Peças', 'VENDEDOR_PECAS_NUMERO', defaultInternalNumber),
  recuperacao: buildSellerProfile('VENDEDOR_RECUPERACAO', 'Closer Recuperação', 'VENDEDOR_RECUPERACAO_NUMERO', defaultInternalNumber),
  atendimento_humano: buildSellerProfile('VENDEDOR_ATENDIMENTO_HUMANO', 'Fila Atendimento Humano', 'VENDEDOR_ATENDIMENTO_HUMANO_NUMERO', defaultInternalNumber)
};

const salesRulesText = [
  'Regras de direcionamento interno:',
  '- se houver risco, reclamação séria ou necessidade humana clara, use atendimento_humano.',
  '- se o lead estiver muito quente e urgente, pode usar premium.',
  '- se o contexto indicar climatização, priorize climatizacao.',
  '- se o contexto indicar refrigeração/bebidas, priorize refrigeracao.',
  '- se o contexto indicar peças, instalação, manutenção ou ferramenta, priorize pecas.',
  '- se o contexto indicar linha branca/eletroportáteis, priorize eletro.',
  '- quando nada for claro ou o lead ainda estiver morno, use recuperacao.'
].join('\n');

const gestorPrompt = [
  'Analise esta conversa de atendimento do WhatsApp da Frigelar.',
  'Use a memória compartilhada da sessão para considerar até as últimas 15 mensagens trocadas entre cliente e atendimento.',
  'Conte apenas mensagens úteis da conversa. Ignore eventuais trechos internos, JSONs e ruídos técnicos da memória.',
  'Se houver menos de 15 mensagens úteis disponíveis, informe isso claramente no JSON.',
  '',
  `Nome do cliente: ${safeText(j.first_name || j.customer_name, 'Cliente')}`,
  `Telefone: ${safeText(j.whatsapp_number, '')}`,
  `Mensagem atual do cliente: ${safeText(j.user_message, '')}`,
  `Resposta comercial preparada ao cliente: ${safeText(j.specialist_reply_text, '')}`,
  `Especialista acionado: ${safeText(j.specialist, '')}`,
  `Etapa do lead: ${safeText(j.lead_stage, 'avaliacao')}`,
  `Segmento inferido: ${segmento}`,
  `Resumo do site/contexto: ${safeText(j.site_context_summary, '')}`,
  `Link do carrinho: ${safeText(j.cart_url, '')}`,
  `Links de produto: ${safeText(j.top_product_links_text, '')}`,
  `Links de categoria: ${safeText(j.top_category_links_text, '')}`,
  j.whatsapp_send_status ? `Status do envio ao cliente: ${safeText(j.whatsapp_send_status, '')}` : '',
  '',
  'Perfis de vendedor disponíveis:',
  Object.entries(sellerPool).map(([key, value]) => `- ${key}: ${value.nome} | contato: ${value.numero}`).join('\n'),
  '',
  salesRulesText,
  '',
  'Retorne somente JSON válido neste formato:',
  '{',
  '  "nome_cliente": "...",',
  '  "telefone": "...",',
  '  "momento_atendimento": "...",',
  '  "quantidade_mensagens_analisadas": 0,',
  '  "atingiu_janela_15_mensagens": false,',
  '  "resumo_ultimas_15_mensagens": "...",',
  '  "sinais_de_interesse": ["..."],',
  '  "principais_objecoes": ["..."],',
  '  "nivel_de_engajamento": "Alto",',
  '  "urgencia_percebida": "Média",',
  '  "score_conversao": 0,',
  '  "classificacao_lead": "Médio potencial",',
  '  "perfil_vendedor_indicado": "recuperacao",',
  '  "recomendacao_comercial": "...",',
  '  "justificativa_direcionamento": "..."',
  '}'
].filter(Boolean).join('\n');

return [{
  json: {
    ...j,
    segmento_atendimento: segmento,
    vendedor_pool: sellerPool,
    default_internal_number: defaultInternalNumber,
    gestor_prompt: gestorPrompt
  }
}];

function safeText(value, fallback = '') {
  const text = String(value || '').trim();
  return text || String(fallback || '').trim();
}

function parseJson(rawValue) {
  if (rawValue && typeof rawValue === 'object' && !Array.isArray(rawValue)) return rawValue;

  const raw = String(rawValue || '').trim();
  if (!raw) return {};

  try {
    return JSON.parse(raw);
  } catch (e) {}

  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced) {
    try {
      return JSON.parse(fenced[1]);
    } catch (e) {}
  }

  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start >= 0 && end > start) {
    try {
      return JSON.parse(raw.slice(start, end + 1));
    } catch (e) {}
  }

  return {};
}

function clampScore(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) return 0;
  return Math.max(0, Math.min(100, Math.round(num)));
}

function normalizeList(value) {
  if (Array.isArray(value)) {
    return value.map(item => safeText(item, '')).filter(Boolean).slice(0, 6);
  }
  if (typeof value === 'string') {
    return value
      .split(/\n|;|\|/g)
      .map(item => safeText(item, ''))
      .filter(Boolean)
      .slice(0, 6);
  }
  return [];
}

function normalizeEnum(value, allowed, fallback) {
  const text = safeText(value, fallback);
  return allowed.includes(text) ? text : fallback;
}

function normalizePhone(value, fallback = '') {
  const digits = String(value || fallback || '').replace(/\D/g, '');
  return digits;
}

function classificationFromScore(score) {
  if (score >= 85) return 'Muito alto potencial';
  if (score >= 70) return 'Alto potencial';
  if (score >= 45) return 'Médio potencial';
  return 'Baixo potencial';
}

function boolFromAny(value) {
  if (typeof value === 'boolean') return value;
  return /^(true|1|sim|yes)$/i.test(String(value || '').trim());
}

function resolveSellerProfile(pool, profile, segment, defaultNumber) {
  if (profile && pool[profile]) return pool[profile];
  if (segment && pool[segment]) return pool[segment];
  return pool.recuperacao || { nome: 'Closer Recuperação', numero: defaultNumber };
}

const ctx = $('BACKOFFICE | 20 Code Preparar Contexto Gestor').item.json;
const raw = $json.output || $json;
const parsed = parseJson(raw);
const pool = ctx.vendedor_pool || {};
const defaultNumber = safeText(ctx.default_internal_number, '555192875343');

const score = clampScore(parsed.score_conversao);
const classificacao = normalizeEnum(
  parsed.classificacao_lead,
  ['Muito alto potencial', 'Alto potencial', 'Médio potencial', 'Baixo potencial'],
  classificationFromScore(score)
);

const nivelEngajamento = normalizeEnum(
  parsed.nivel_de_engajamento,
  ['Alto', 'Médio', 'Baixo'],
  score >= 75 ? 'Alto' : score >= 45 ? 'Médio' : 'Baixo'
);

const urgencia = normalizeEnum(
  parsed.urgencia_percebida,
  ['Alta', 'Média', 'Baixa'],
  'Média'
);

const quantidadeMensagens = Math.max(0, Math.round(Number(parsed.quantidade_mensagens_analisadas || 0)));
const atingiuJanela15 = boolFromAny(parsed.atingiu_janela_15_mensagens) || quantidadeMensagens >= 15;

const profile = safeText(parsed.perfil_vendedor_indicado, '');
const sellerProfile = resolveSellerProfile(pool, profile, ctx.segmento_atendimento, defaultNumber);
const vendedorNome = safeText(sellerProfile.nome, 'Closer Recuperação');
const vendedorNumero = normalizePhone(sellerProfile.numero, defaultNumber);

const sinais = normalizeList(parsed.sinais_de_interesse);
const objecoes = normalizeList(parsed.principais_objecoes);

const resumo = safeText(
  parsed.resumo_ultimas_15_mensagens,
  `Cliente em etapa ${safeText(ctx.lead_stage, 'avaliacao')} com mensagem atual: ${safeText(ctx.user_message, '')}`
).slice(0, 900);

const recomendacao = safeText(
  parsed.recomendacao_comercial,
  score >= 70
    ? 'Lead aquecido. Priorizar resposta rápida, reduzir atrito e levar para o próximo passo com clareza.'
    : score >= 45
      ? 'Lead em avaliação. Trabalhar objeções e manter condução consultiva sem pressão.'
      : 'Lead frio ou inseguro. Nutrir com abordagem simples, objetiva e pouco invasiva.'
);

const justificativa = safeText(
  parsed.justificativa_direcionamento,
  `Direcionamento definido pelo segmento ${safeText(ctx.segmento_atendimento, 'recuperacao')}, score ${score} e urgência ${urgencia.toLowerCase()}.`
);

const shouldNotify = Boolean(ctx.needs_human) || (atingiuJanela15 && (
  ['Muito alto potencial', 'Alto potencial'].includes(classificacao) || urgencia === 'Alta'
));

const mensagemInterna = [
  '🔎 Gestor de Vendas | Lead analisado',
  `Cliente: ${safeText(parsed.nome_cliente, safeText(ctx.first_name || ctx.customer_name, 'Cliente'))}`,
  `Telefone: ${normalizePhone(parsed.telefone, ctx.whatsapp_number)}`,
  `Momento: ${safeText(parsed.momento_atendimento, safeText(ctx.lead_stage, 'avaliacao'))}`,
  `Especialista atual: ${safeText(ctx.specialist, '')}`,
  `Mensagens consideradas: ${quantidadeMensagens}`,
  `Janela de 15 mensagens atingida: ${atingiuJanela15 ? 'Sim' : 'Não'}`,
  `Score: ${score}/100`,
  `Classificação: ${classificacao}`,
  `Engajamento: ${nivelEngajamento}`,
  `Urgência: ${urgencia}`,
  `Perfil indicado: ${safeText(profile, safeText(ctx.segmento_atendimento, 'recuperacao'))}`,
  `Vendedor indicado: ${vendedorNome}`,
  `Sinais de interesse: ${sinais.length ? sinais.join(', ') : 'Não identificados com clareza'}`,
  `Principais objeções: ${objecoes.length ? objecoes.join(', ') : 'Sem objeções claras até agora'}`,
  `Resumo: ${resumo}`,
  `Recomendação comercial: ${recomendacao}`,
  `Justificativa do direcionamento: ${justificativa}`,
  ctx.recommended_link ? `Link recomendado: ${ctx.recommended_link}` : '',
  ctx.cart_url ? `Carrinho: ${ctx.cart_url}` : ''
].filter(Boolean).join('\n');

return [{
  json: {
    ...ctx,
    nome_cliente: safeText(parsed.nome_cliente, safeText(ctx.first_name || ctx.customer_name, 'Cliente')),
    telefone: normalizePhone(parsed.telefone, ctx.whatsapp_number),
    momento_atendimento: safeText(parsed.momento_atendimento, safeText(ctx.lead_stage, 'avaliacao')),
    quantidade_mensagens_analisadas: quantidadeMensagens,
    atingiu_janela_15_mensagens: atingiuJanela15 ? 'SIM' : 'NAO',
    resumo_ultimas_15_mensagens: resumo,
    sinais_de_interesse: sinais,
    principais_objecoes: objecoes,
    nivel_de_engajamento: nivelEngajamento,
    urgencia_percebida: urgencia,
    score_conversao: score,
    classificacao_lead: classificacao,
    recomendacao_comercial: recomendacao,
    vendedor_indicado_perfil: safeText(profile, safeText(ctx.segmento_atendimento, 'recuperacao')),
    vendedor_indicado_nome: vendedorNome,
    vendedor_indicado_numero: vendedorNumero,
    justificativa_direcionamento: justificativa,
    should_notify_internal: shouldNotify ? 'SIM' : 'NAO',
    mensagem_interna_apoio_comercial: mensagemInterna,
    raw_gestor_output: typeof raw === 'string' ? raw : JSON.stringify(raw)
  }
}];
